/* ============================================================
   HealthSense AI Chat Widget — Premium Custom Theme
   ============================================================
   Paste this entire block into your Chat Trigger node's
   "Custom Chat Styling" field (Options → Custom CSS).

   Bot Name (set in node): HealthSense AI
   Design: Light green brand with smooth animations,
   refined typography, and professional micro-interactions.
   ============================================================ */

/* ─── Google Fonts Import ─── */
@import url('https://fonts.googleapis.com/css2?family=DM+Sans:ital,opsz,wght@0,9..40,300;0,9..40,400;0,9..40,500;0,9..40,600;0,9..40,700;1,9..40,400&family=JetBrains+Mono:wght@400;500&display=swap');

/* ─── CSS Variables (Root Overrides) ─── */
:root {
  /* ── Brand Colors ── */
  --chat--color-primary: #3DAA6E;
  --chat--color-primary-shade-50: #2E9459;
  --chat--color-primary-shade-100: #1F7A45;
  --chat--color-secondary: #90DBA8;
  --chat--color-secondary-shade-50: #72C98F;
  --chat--color-white: #FFFFFF;
  --chat--color-light: #F0F2F8;
  --chat--color-light-shade-50: #E2E5EF;
  --chat--color-light-shade-100: #B8BDD0;
  --chat--color-medium: #A0A4B8;
  --chat--color-dark: #1A1B2E;
  --chat--color-disabled: #C5C8D8;
  --chat--color-typing: #6B6E85;

  /* ── Layout ── */
  --chat--spacing: 1rem;
  --chat--border-radius: 1rem;
  --chat--transition-duration: 0.25s;
  --chat--font-family: 'DM Sans', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;

  /* ── Window ── */
  --chat--window--width: 420px;
  --chat--window--height: 640px;
  --chat--window--bottom: 1.25rem;
  --chat--window--right: 1.25rem;
  --chat--window--z-index: 9999;
  --chat--window--border: 1px solid rgba(61, 170, 110, 0.15);
  --chat--window--border-radius: 1.25rem;
  --chat--window--margin-bottom: var(--chat--spacing);

  /* ── Header ── */
  --chat--header-height: auto;
  --chat--header--padding: 1.25rem 1.5rem;
  --chat--header--background: #3DB870;
  --chat--header--color: #F0F2F8;
  --chat--header--border-top: none;
  --chat--header--border-bottom: 1px solid rgba(61, 170, 110, 0.3);
  --chat--header--border-left: none;
  --chat--header--border-right: none;
  --chat--heading--font-size: 4em;
  --chat--subtitle--font-size: 0.85rem;
  --chat--subtitle--line-height: 1.6;

  /* ── Messages ── */
  --chat--message--font-size: 0.9375rem;
  --chat--message--padding: 0.875rem 1.1rem;
  --chat--message--border-radius: 1.125rem;
  --chat--message-line-height: 1.65;
  --chat--message--margin-bottom: 0.625rem;
  --chat--message--bot--background: #FFFFFF;
  --chat--message--bot--color: #2D2E4A;
  --chat--message--bot--border: 1px solid rgba(0, 0, 0, 0.04);
  --chat--message--user--background: linear-gradient(135deg, #3DAA6E, #62C98A);
  --chat--message--user--color: #FFFFFF;
  --chat--message--user--border: none;
  --chat--message--pre--background: rgba(61, 170, 110, 0.06);
  --chat--messages-list--padding: 1.25rem;

  /* ── Toggle Button ── */
  --chat--toggle--size: 60px;
  --chat--toggle--width: var(--chat--toggle--size);
  --chat--toggle--height: var(--chat--toggle--size);
  --chat--toggle--border-radius: 1rem;
  --chat--toggle--background: linear-gradient(135deg, #3DAA6E, #62C98A);
  --chat--toggle--hover--background: linear-gradient(135deg, #2E9459, #50B878);
  --chat--toggle--active--background: linear-gradient(135deg, #1F7A45, #3DAA6E);
  --chat--toggle--color: var(--chat--color-white);

  /* ── Input ── */
  --chat--textarea--height: 52px;
  --chat--textarea--max-height: 12rem;
  --chat--input--font-size: 0.9375rem;
  --chat--input--border: 1px solid #E2E5EF;
  --chat--input--border-radius: 0.875rem;
  --chat--input--padding: 0.875rem 1rem;
  --chat--input--background: #FFFFFF;
  --chat--input--text-color: #2D2E4A;
  --chat--input--line-height: 1.5;
  --chat--input--placeholder--font-size: 0.9375rem;
  --chat--input--border-active: 1px solid rgba(61, 170, 110, 0.5);
  --chat--input--left--panel--width: 2rem;

  /* ── Buttons ── */
  --chat--button--color: #FFFFFF;
  --chat--button--background: linear-gradient(135deg, #3DAA6E, #62C98A);
  --chat--button--padding: 0.5rem 1.25rem;
  --chat--button--border-radius: 0.75rem;
  --chat--button--hover--color: #FFFFFF;
  --chat--button--hover--background: linear-gradient(135deg, #2E9459, #50B878);
  --chat--close--button--color-hover: #3DAA6E;

  /* ── Send / File Buttons ── */
  --chat--input--send--button--background: transparent;
  --chat--input--send--button--color: #3DAA6E;
  --chat--input--send--button--background-hover: rgba(61, 170, 110, 0.1);
  --chat--input--send--button--color-hover: #2E9459;
  --chat--input--file--button--background: transparent;
  --chat--input--file--button--color: #A0A4B8;
  --chat--input--file--button--background-hover: rgba(61, 170, 110, 0.08);
  --chat--input--file--button--color-hover: #3DAA6E;
  --chat--files-spacing: 0.375rem;

  /* ── Body / Footer ── */
  --chat--body--background: #F5F6FB;
  --chat--footer--background: #FFFFFF;
  --chat--footer--color: #2D2E4A;
}

/* ─── Window Container ─── */
.chat-window {
  box-shadow:
    0 8px 32px rgba(26, 27, 46, 0.12),
    0 2px 8px rgba(61, 170, 110, 0.08) !important;
  backdrop-filter: blur(10px) !important;
  overflow: hidden !important;
  transition: all 0.35s cubic-bezier(0.4, 0, 0.2, 1) !important;
}

/* ─── Header ─── */
.chat-header {
  position: relative !important;
  overflow: hidden !important;
}

/* Decorative gradient accent line under header */
.chat-header::after {
  content: '' !important;
  position: absolute !important;
  bottom: 0 !important;
  left: 0 !important;
  right: 0 !important;
  height: 2px !important;
  background: linear-gradient(90deg, #3DB870, #90DBA8, #3DB870) !important;
  background-size: 200% 100% !important;
  animation: shimmer 3s ease-in-out infinite !important;
}

@keyframes shimmer {
  0%, 100% { background-position: 0% 50%; }
  50%       { background-position: 100% 50%; }
}

/* Header title styling */
.chat-header p:first-child,
.chat-header .chat-heading {
  font-weight: 700 !important;
  letter-spacing: -0.02em !important;
}

.chat-header p:last-child,
.chat-header .chat-subtitle {
  opacity: 0.7 !important;
  font-weight: 400 !important;
  font-size: 0.8rem !important;
}

/* ─── Messages Area ─── */
.chat-messages-list,
.chat-body {
  background: #F5F6FB !important;
  background-image:
    radial-gradient(circle at 20% 80%, rgba(61, 170, 110, 0.03) 0%, transparent 50%),
    radial-gradient(circle at 80% 20%, rgba(144, 219, 168, 0.03) 0%, transparent 50%) !important;
}

/* Smooth scroll */
.chat-messages-list {
  scroll-behavior: smooth !important;
  scrollbar-width: thin !important;
  scrollbar-color: rgba(61, 170, 110, 0.2) transparent !important;
}
.chat-messages-list::-webkit-scrollbar       { width: 5px !important; }
.chat-messages-list::-webkit-scrollbar-track { background: transparent !important; }
.chat-messages-list::-webkit-scrollbar-thumb {
  background: rgba(61, 170, 110, 0.2) !important;
  border-radius: 10px !important;
}
.chat-messages-list::-webkit-scrollbar-thumb:hover {
  background: rgba(61, 170, 110, 0.35) !important;
}

/* ─── Message Bubbles ─── */
.chat-message {
  max-width: 82% !important;
  font-family: 'DM Sans', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif !important;
  animation: messageSlideIn 0.35s cubic-bezier(0.4, 0, 0.2, 1) !important;
  position: relative !important;
  word-wrap: break-word !important;
  transition: transform 0.15s ease !important;
}

@keyframes messageSlideIn {
  0%   { opacity: 0; transform: translateY(12px) scale(0.97); }
  100% { opacity: 1; transform: translateY(0)    scale(1);    }
}

/* Bot messages */
.chat-message.chat-message-from-bot {
  background: #FFFFFF !important;
  color: #2D2E4A !important;
  border: 1px solid rgba(0, 0, 0, 0.04) !important;
  border-radius: 1.125rem 1.125rem 1.125rem 0.375rem !important;
  box-shadow: 0 1px 4px rgba(26, 27, 46, 0.06) !important;
}

/* User messages */
.chat-message.chat-message-from-user {
  background: linear-gradient(135deg, #3DAA6E, #62C98A) !important;
  color: #FFFFFF !important;
  border-radius: 1.125rem 1.125rem 0.375rem 1.125rem !important;
  box-shadow: 0 2px 8px rgba(61, 170, 110, 0.25) !important;
}

/* Message paragraph spacing */
.chat-message p {
  margin-top: 0.2em !important;
  margin-bottom: 0.2em !important;
  line-height: 1.65 !important;
}

/* Links inside messages */
.chat-message a {
  color: #3DAA6E !important;
  text-decoration: underline !important;
  text-decoration-color: rgba(61, 170, 110, 0.3) !important;
  text-underline-offset: 2px !important;
  transition: text-decoration-color 0.2s ease !important;
}
.chat-message a:hover {
  text-decoration-color: #3DAA6E !important;
}
.chat-message-from-user a {
  color: #FFFFFF !important;
  text-decoration-color: rgba(255, 255, 255, 0.4) !important;
}

/* Code blocks in messages */
.chat-message pre {
  background: #EEF7F1 !important;
  border: 1px solid rgba(61, 170, 110, 0.1) !important;
  border-radius: 0.625rem !important;
  padding: 0.75rem 1rem !important;
  font-family: 'JetBrains Mono', 'Fira Code', monospace !important;
  font-size: 0.8125rem !important;
  overflow-x: auto !important;
  margin: 0.5rem 0 !important;
}
.chat-message code {
  font-family: 'JetBrains Mono', 'Fira Code', monospace !important;
  font-size: 0.84em !important;
  background: rgba(61, 170, 110, 0.08) !important;
  padding: 0.15em 0.4em !important;
  border-radius: 0.3em !important;
  color: #2E9459 !important;
}
.chat-message-from-user code {
  background: rgba(255, 255, 255, 0.2) !important;
  color: #FFFFFF !important;
}

/* Lists inside messages */
.chat-message ul,
.chat-message ol {
  padding-left: 1.25rem !important;
  margin: 0.35rem 0 !important;
}
.chat-message li {
  margin-bottom: 0.2rem !important;
  line-height: 1.6 !important;
}

/* ─── Typing Indicator ─── */
.chat-message-typing {
  display: flex !important;
  align-items: center !important;
  gap: 5px !important;
  padding: 0.875rem 1.1rem !important;
}
.chat-message-typing span,
.chat-message-typing .dot {
  animation: typingBounce 1.2s ease-in-out infinite !important;
}
@keyframes typingBounce {
  0%, 60%, 100% { transform: translateY(0);    opacity: 0.4; }
  30%           { transform: translateY(-4px); opacity: 1;   }
}

/* ─── Input / Footer Area ─── */
.chat-footer {
  background: #FFFFFF !important;
  border-top: 1px solid rgba(0, 0, 0, 0.06) !important;
  padding: 0.75rem 1rem !important;
}

.chat-input {
  font-family: 'DM Sans', -apple-system, BlinkMacSystemFont, sans-serif !important;
  font-size: 0.9375rem !important;
  border: 1.5px solid #E2E5EF !important;
  border-radius: 0.875rem !important;
  transition: all 0.2s ease !important;
  background: #FAFBFE !important;
  color: #2D2E4A !important;
}
.chat-input:focus,
.chat-input:focus-within {
  border-color: rgba(61, 170, 110, 0.5) !important;
  box-shadow: 0 0 0 3px rgba(61, 170, 110, 0.08) !important;
  background: #FFFFFF !important;
  outline: none !important;
}
.chat-input::placeholder,
.chat-input textarea::placeholder {
  color: #B8BDD0 !important;
  font-style: normal !important;
}

/* Input wrapper / container */
.chat-input-wrapper,
.chat-inputs { gap: 0.5rem !important; }

/* Textarea within input */
.chat-input textarea {
  font-family: 'DM Sans', -apple-system, BlinkMacSystemFont, sans-serif !important;
  color: #2D2E4A !important;
}

/* ─── Send Button ─── */
.chat-input-send-button {
  border-radius: 0.75rem !important;
  transition: all 0.2s ease !important;
  display: flex !important;
  align-items: center !important;
  justify-content: center !important;
}
.chat-input-send-button:hover  { transform: scale(1.05) !important; background: rgba(61, 170, 110, 0.12) !important; }
.chat-input-send-button:active { transform: scale(0.95) !important; }

/* ─── Toggle (Chat Bubble Button) ─── */
.chat-toggle {
  box-shadow:
    0 4px 16px rgba(61, 170, 110, 0.3),
    0 2px 6px rgba(26, 27, 46, 0.1) !important;
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1) !important;
}
.chat-toggle:hover {
  transform: scale(1.06) translateY(-2px) !important;
  box-shadow:
    0 8px 24px rgba(61, 170, 110, 0.4),
    0 4px 8px rgba(26, 27, 46, 0.1) !important;
}
.chat-toggle:active { transform: scale(0.96) !important; }

/* ─── Welcome / Get Started Screen ─── */
.chat-get-started,
.chat-welcome {
  background: linear-gradient(180deg, #F5F6FB 0%, #EEF7F1 100%) !important;
  display: flex !important;
  flex-direction: column !important;
  align-items: center !important;
  justify-content: center !important;
  text-align: center !important;
  padding: 2.5rem !important;
}
.chat-get-started p,
.chat-welcome p {
  color: #6B6E85 !important;
  font-size: 0.9375rem !important;
  line-height: 1.6 !important;
  max-width: 300px !important;
}
.chat-get-started button,
.chat-welcome button {
  background: linear-gradient(135deg, #3DAA6E, #62C98A) !important;
  color: #FFFFFF !important;
  border: none !important;
  border-radius: 0.75rem !important;
  padding: 0.7rem 2rem !important;
  font-family: 'DM Sans', sans-serif !important;
  font-weight: 600 !important;
  font-size: 0.9375rem !important;
  cursor: pointer !important;
  transition: all 0.25s cubic-bezier(0.4, 0, 0.2, 1) !important;
  box-shadow: 0 4px 12px rgba(61, 170, 110, 0.25) !important;
  margin-top: 1rem !important;
}
.chat-get-started button:hover,
.chat-welcome button:hover {
  transform: translateY(-1px) !important;
  box-shadow: 0 6px 20px rgba(61, 170, 110, 0.35) !important;
}

/* ─── Close Button ─── */
.chat-close-button {
  transition: all 0.2s ease !important;
  border-radius: 0.5rem !important;
  opacity: 0.7 !important;
}
.chat-close-button:hover {
  opacity: 1 !important;
  background: rgba(255, 255, 255, 0.1) !important;
}

/* ─── File Upload Area ─── */
.chat-files,
.chat-file {
  border-radius: 0.625rem !important;
  border: 1px solid rgba(61, 170, 110, 0.15) !important;
  background: rgba(61, 170, 110, 0.04) !important;
  transition: all 0.2s ease !important;
}

/* ─── Powered By Footer ─── */
.chat-footer a,
.chat-powered-by {
  opacity: 0.4 !important;
  font-size: 0.7rem !important;
  transition: opacity 0.2s ease !important;
}
.chat-footer a:hover,
.chat-powered-by:hover { opacity: 0.65 !important; }

/* ─── Selection Color ─── */
.chat-window ::selection {
  background: rgba(61, 170, 110, 0.2) !important;
  color: #2D2E4A !important;
}

/* ─── Responsive Adjustments ─── */
@media (max-width: 480px) {
  :root {
    --chat--window--width: calc(100vw - 2rem) !important;
    --chat--window--height: calc(100vh - 6rem) !important;
    --chat--window--right: 1rem !important;
    --chat--window--bottom: 1rem !important;
  }
  .chat-message { max-width: 88% !important; }
}

/* ─── Reduced Motion ─── */
@media (prefers-reduced-motion: reduce) {
  .chat-message          { animation: none !important; }
  .chat-header::after    { animation: none !important; }
  .chat-toggle:hover     { transform: none !important; }
}
